def verify_hmac_signature(payload_body: bytes, signature_header: str, secret: str) -> bool:
    """Verify the HMAC-SHA256 signature of the webhook payload."""
    if not signature_header or not secret:
        return False

    # Support different signature formats
    # Format: sha256=<hex_digest> or just <hex_digest>
    if signature_header.startswith("sha256="):
        received_signature = signature_header[7:]
    elif signature_header.startswith("v1="):
        received_signature = signature_header[3:]
    else:
        received_signature = signature_header

    expected_signature = hmac.new(
        secret.encode("utf-8"),
        payload_body,
        hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(expected_signature, received_signature)


def verify_timestamp(timestamp_header: str, tolerance_seconds: int = 300) -> bool:
    """Verify the webhook timestamp is within acceptable range to prevent replay attacks."""
    if not timestamp_header:
        return False

    try:
        webhook_time = int(timestamp_header)
        current_time = int(datetime.now(timezone.utc).timestamp())
        return abs(current_time - webhook_time) <= tolerance_seconds
    except (ValueError, TypeError):
        return False


def verify_ip_allowlist(request_ip: str) -> bool:
    """Verify the request comes from an allowed IP address."""
    if not ALLOWED_IPS or ALLOWED_IPS == [""]:
        # If no IP allowlist is configured, skip this check
        return True
    return request_ip in ALLOWED_IPS


