@functions_framework.http
def payment_webhook(request):
    """
    HTTP Cloud Function endpoint for processing payment webhook events.

    Deploy with:
        gcloud functions deploy payment-webhook \
            --gen2 \
            --runtime=python312 \
            --region=us-central1 \
            --source=. \
            --entry-point=payment_webhook \
            --trigger-http \
            --allow-unauthenticated \
            --set-env-vars="WEBHOOK_SECRET=your-secret-here,ALLOWED_PARTNERS=stripe,paypal,square" \
            --memory=256MB \
            --timeout=60s

    Partners call this endpoint without Google authentication.
    Internal validation is performed via HMAC signatures, IP allowlisting,
    timestamp verification, and payload validation.
    """

    # --- Rate limiting note ---
    # For production, consider using Cloud Armor or API Gateway
    # in front of this function for rate limiting.

    # Only accept POST requests
    if request.method != "POST":
        logger.warning("Rejected non-POST request: method=%s", request.method)
        return (
            json.dumps({"error": "Method not allowed", "allowed_methods": ["POST"]}),
            405,
            {"Content-Type": "application/json"},
        )

    # Check Content-Type
    content_type = request.content_type or ""
    if "application/json" not in content_type:
        logger.warning("Rejected request with invalid content type: %s", content_type)
        return (
            json.dumps({"error": "Content-Type must be application/json"}),
            415,
            {"Content-Type": "application/json"},
        )

    # --- IP Allowlist Verification ---
    request_ip = request.headers.get("X-Forwarded-For", request.remote_addr)
    if request_ip and "," in request_ip:
        # X-Forwarded-For can contain multiple IPs; take the first (client IP)
        request_ip = request_ip.split(",")[0].strip()

    if not verify_ip_allowlist(request_ip):
        logger.warning("Rejected request from non-allowlisted IP: %s", request_ip)
        return (
            json.dumps({"error": "Forbidden"}),
            403,
            {"Content-Type": "application/json"},
        )

    # --- Get raw payload for signature verification ---
    raw_body = request.get_data()
    if not raw_body:
        logger.warning("Rejected request with empty body")
        return (
            json.dumps({"error": "Request body is empty"}),
            400,
            {"Content-Type": "application/json"},
        )

    # --- HMAC Signature Verification ---
    # Support multiple header names used by different payment providers
    signature = (
        request.headers.get("X-Webhook-Signature")
        or request.headers.get("X-Hub-Signature-256")
        or request.headers.get("Stripe-Signature")
        or request.headers.get("X-Signature")
        or ""
    )

    if WEBHOOK_SECRET:
        if not verify_hmac_signature(raw_body, signature, WEBHOOK_SECRET):
            logger.warning(
                "Rejected request with invalid signature from IP=%s",
                request_ip,
            )
            return (
                json.dumps({"error": "Invalid webhook signature"}),
                401,
                {"Content-Type": "application/json"},
            )
    else:
        logger.warning("WEBHOOK_SECRET not configured - signature verification skipped!")

    # --- Timestamp Verification (replay attack prevention) ---
    timestamp = (
        request.headers.get("X-Webhook-Timestamp")
        or request.headers.get("X-Timestamp")
        or ""
    )
    if timestamp:
        if not verify_timestamp(timestamp):
            logger.warning(
                "Rejected request with stale timestamp: %s from IP=%s",
                timestamp,
                request_ip,
            )
            return (
                json.dumps({"error": "Webhook timestamp is too old or invalid"}),
                401,
                {"Content-Type": "application/json"},
            )

    # --- Parse JSON payload ---
    try:
        payload = request.get_json(force=False, silent=False)
        if payload is None:
            raise ValueError("Parsed payload is None")
    except Exception as e:
        logger.warning("Failed to parse JSON payload: %s", str(e))
        return (
            json.dumps({"error": "Invalid JSON payload"}),
            400,
            {"Content-Type": "application/json"},
        )

    # --- Validate payload structure ---
    is_valid, validation_error = validate_payload(payload)
    if not is_valid:
        logger.warning("Payload validation failed: %s", validation_error)
        return (
            json.dumps({"error": validation_error}),
            422,
            {"Content-Type": "application/json"},
        )

    # --- Idempotency Check ---
    event_id = payload.get("event_id", "")
    if event_id:
        if check_idempotency(event_id):
            logger.info("Duplicate event detected, skipping: event_id=%s", event_id)
            return (
                json.dumps({
                    "status": "already_processed",
                    "event_id": event_id,
                    "message": "This event has already been processed",
                }),
                200,
                {"Content-Type": "application/json"},
            )

    # --- Route to appropriate handler ---
    event_type = payload["event_type"]
    handler = EVENT_HANDLERS.get(event_type)

    if not handler:
        logger.error("No handler found for event type: %s", event_type)
        return (
            json.dumps({"error": f"Unhandled event type: {event_type}"}),
            422,
            {"Content-Type": "application/json"},
        )

    try:
        result = handler(payload)
        logger.info(
            "Successfully processed webhook: event_type=%s, event_id=%s, partner=%s",
            event_type,
            event_id,
            payload.get("partner_id"),
        )

        response = {
            "status": "success",
            "event_id": event_id,
            "event_type": event_type,
            "result": result,
            "processed_at": datetime.now(timezone.utc).isoformat(),
        }

        return (
            json.dumps(response),
            200,
            {"Content-Type": "application/json"},
        )

    except Exception as e:
        logger.exception(
            "Error processing webhook: event_type=%s, event_id=%s, error=%s",
            event_type,
            event_id,
            str(e),
        )
        # Return 500 so the partner will retry
        return (
            json.dumps({
                "error": "Internal processing error",
                "event_id": event_id,
                "message": "Please retry later",
            }),
            500,
            {"Content-Type": "application/json"},
        )